import pytest
import requests

def test_allergy_recorded_date_boundary_max_precision(auth_token, patient_id, base_url, cleanup_resource):
    headers = {"Authorization": f"Bearer {auth_token}", "Content-Type": "application/fhir+json"}
    base_payload = {
        "resourceType": "AllergyIntolerance",
        "clinicalStatus": {"coding": [{"system": "http://terminology.hl7.org/CodeSystem/allergyintolerance-clinical", "code": "active"}]},
        "verificationStatus": {"coding": [{"system": "http://terminology.hl7.org/CodeSystem/allergyintolerance-verification", "code": "confirmed"}]},
        "code": {"coding": [{"system": "http://www.nlm.nih.gov/research/umls/rxnorm", "code": "3498", "display": "Aspirin"}]},
        "patient": {"reference": f"Patient/{patient_id}"}
    }
    full_ts_payload = {**base_payload, "recordedDate": "2024-12-31T23:59:59.999+00:00"}
    r1 = requests.post(f"{base_url}/AllergyIntolerance", json=full_ts_payload, headers=headers)
    assert r1.status_code == 201, f"Full-precision timestamp rejected: {r1.status_code} {r1.text}"
    rid1 = r1.headers["Location"].rstrip("/").split("/")[-1].split("/_history")[0]
    cleanup_resource("AllergyIntolerance", rid1)
    stored = requests.get(f"{base_url}/AllergyIntolerance/{rid1}", headers=headers).json()
    assert "2024-12-31" in stored.get("recordedDate", ""), "Date portion must be preserved"
    date_only_payload = {**base_payload, "recordedDate": "2024-12-31"}
    r2 = requests.post(f"{base_url}/AllergyIntolerance", json=date_only_payload, headers=headers)
    assert r2.status_code == 201, f"Date-only timestamp rejected: {r2.status_code} {r2.text}"
    rid2 = r2.headers["Location"].rstrip("/").split("/")[-1].split("/_history")[0]
    cleanup_resource("AllergyIntolerance", rid2)
